const now = new Date();

function diffDays(dateString) {
  if (!dateString) return 9999;
  const date = new Date(dateString);
  const diffMs = now - date;
  return Math.floor(diffMs / (1000 * 60 * 60 * 24));
}

function getScoreRecencia(days) {
  if (days <= 3) return 30;
  if (days <= 7) return 25;
  if (days <= 15) return 18;
  if (days <= 30) return 10;
  return 0;
}

function getScoreUrgencia(days) {
  if (days > 90) return 50;
  if (days > 60) return 35;
  if (days > 30) return 20;
  if (days > 15) return 10;
  return 0;
}

function getPrioridade(score) {
  if (score >= 80) return "Prioridade Máxima";
  if (score >= 60) return "Alta";
  if (score >= 40) return "Média";
  return "Baixa";
}

function getSegmento(nota, diasSemContato) {
  if (diasSemContato > 45) return "urgente_reengajar";
  if (nota >= 8 && diasSemContato <= 7) return "quente_recente";
  if (nota >= 7 && diasSemContato > 15) return "esfriando";
  if (nota < 5) return "baixo_potencial";
  return "normal";
}

const output = items.map(item => {
  const nota = item.json.property_nota ?? 0;
  const ultAtividade = item.json.property_ult_atividade?.start || null;

  const diasSemContato = diffDays(ultAtividade);

  const scoreNota = nota * 5;
  const scoreRecencia = getScoreRecencia(diasSemContato);
  const scoreUrgencia = getScoreUrgencia(diasSemContato);

  const scoreFinal = scoreNota + scoreRecencia + scoreUrgencia;

  return {
    json: {
      ...item.json,
      diasSemContato,
      scoreNota,
      scoreRecencia,
      scoreUrgencia,
      scoreFinal,
      prioridade: getPrioridade(scoreFinal),
      segmento: getSegmento(nota, diasSemContato)
    }
  };
});

// ordena do maior para o menor
